mapper.select:
SELECT
    COUNT(*)                         AS totalRefundCount,
    COALESCE(SUM(r.amount), 0)       AS totalRefundedAmount,
    ROUND(
        COUNT(*) / NULLIF(
            (SELECT COUNT(*) FROM orders
             WHERE paid_at IS NOT NULL
               AND paid_at >= #{rangeFrom} AND paid_at < #{rangeTo}
            ), 0
        ), 4
    ) AS refundRate
FROM refunds r
WHERE r.status = 'SUCCEEDED'
  AND r.created_at >= #{rangeFrom} AND r.created_at < #{rangeTo}

SELECT p.id AS productId, p.name AS productName, p.type AS productType, SUM(oi.unit_price * oi.qty) AS totalRevenue, SUM(oi.qty) AS totalQuantity FROM order_items oi JOIN orders o ON oi.order_id = o.id JOIN products p ON oi.product_id = p.id WHERE o.paid_at IS NOT NULL AND o.status NOT IN () AND o.paid_at >= #{rangeFrom} AND o.paid_at < #{rangeTo} GROUP BY p.id, p.name, p.type ORDER BY
totalRevenue DESC totalQuantity DESC
LIMIT #{limit}
